from sys import stdin
from collections import defaultdict
class Solution:
    def find(self, x, disc, low, parent, timer, graph):
        if disc[x] == -1:
            disc[x] = low[x] = timer += 1
            for v in graph[x]:
                if v == parent[x]:
                    continue
                y = self.find(v, disc, low, parent, timer, graph)
                if y != -1:
                    low[x] = min(low[x], low[y])
                if y == parent[x]:
                    low[x] = min(low[x], disc[x])
                if low[y] > disc[x]:
                    return x
            return -1
        return -1
    def solve(self):
        n = int(stdin.readline())
        disc = [None]*n
        low = [None]*n
        parent = [None]*n
        timer = 0
        graph = defaultdict(list)
        for _ in range(n-1):
            x, y = map(int, stdin.readline().split())
            graph[x].append(y)
            graph[y].append(x)

        for i in range(n):
            if disc[i] == None:
                res = self.find(i, disc, low, parent, timer, graph)
                if res != -1:
                    return res
        return -1

if __name__ == '__main__':
    s = Solution()
    print(s.solve())

