#include <bits/stdc++.h>
class Solution {
public:
    int find(int x, std::vector<int>& disc, std::vector<int>& low, std::vector<int>& parent, int& timer, std::vector<int>& graph) {
        if (disc[x] == -1) {
            disc[x] = low[x] = timer++;
            for (int v : graph[x]) {
                if (v == parent[x]) continue;
                int y = find(v, disc, low, parent, timer, graph);
                if (y != -1) low[x] = std::min(low[x], low[y]);
                if (y == parent[x]) low[x] = std::min(low[x], disc[x]);
                if (low[y] > disc[x]) return x;
            }
            return -1;
        }
        return -1;
    }
    void solve() {
        int n;
        std::cin >> n;
        std::vector<int> disc(n, -1);
        std::vector<int> low(n, -1);
        std::vector<int> parent(n, -1);
        int timer = 0;
        std::vector<int> graph(n);
        for (int i = 0; i < n - 1; i++) {
            int x, y;
            std::cin >> x >> y;
            graph[x].push_back(y);
            graph[y].push_back(x);
        }
        for (int i = 0; i < n; i++) {
            if (disc[i] == -1) {
                int res = find(i, disc, low, parent, timer, graph);
                if (res != -1) {
                    std::cout << res << std::endl;
                    return;
                }
            }
        }
        std::cout << -1 << std::endl;
    }
};
int main() {
    Solution s;
    s.solve();
    return 0;
}
